              pb: ["nutri_lok_jv_autre_feculents","nutri_lok_jv_autre_lait_solide_important"],
              sublabels: { "nutri_lok_jv_autre_feculents": "Féculents", "nutri_lok_jv_autre_lait_solide_important": "Lait/solide imp." },
